// ── Mutable slot holders for late binding ──────────────────────────────────

// Plain objects with a `current` field — same shape as a ref so consumers can
// destructure naturally.  These get populated as the factories run; bindings
// reference `holder.current!.method(...)` lazily so the cycle works.
export type Holder<T> = { current: T | null }

/**
 * Extract Holder.current and assert non-null before returning — the return
 * type is T instead of T | null, so that `const bindings = expectHolderValue(...)`
 * inside a factory won't lose narrowing when used in nested closures.
 * (A plain `const x = holder.current; if (!x) throw` can lose narrowing inside
 * nested async function closures, producing a bunch of "possibly null" errors.)
 */
export function expectHolderValue<T>(holder: Holder<T>, message: string): T {
  if (holder.current === null) {
    throw new Error(message)
  }
  return holder.current
}

// ── The bag itself ──────────────────────────────────────────────────────────

export type VoiceRuntimeBag = {
  ctx: UseVoiceContext
  refs: VoiceRefs
  setters: VoiceSetters
  hookCallbacks: VoiceHookCallbacks
  hearingRuntime: HearingRuntime
  voiceBus: VoiceBus
  // Cross-factory holders — populated as createXxx(bag) runs.
  bindingsHolder: Holder<VoiceBindings>
  enginesHolder: Holder<VoiceEngines>
  lifecycleHolder: Holder<VoiceLifecycle>
  // Tunables (constants from useVoice)
  tunables: {
    voiceTranscriptDedupWindowMs: number
    maxContinuousNoSpeechRestarts: number
    browserTtsLipsyncIntervalMs: number
    audioTtsAnalyserFftSize: number
  }
}
